import spoon.reflect.visitor.filter.TypeFilter;
import spoon.support.compiler.jdt.JDTBasedSpoonCompiler;

import java.io.File;
import java.util.List;

/**
 * Generic Spoon transformation to fix Jakarta Servlet API migration issues.
 * This transformation replaces javax.servlet imports and references with jakarta.servlet
 * for any project migrating from servlet 4.x to 6.0.0.
 */
public class Main {
    public static void main(String[] args) {
        // Check if input directory was provided
        if (args.length == 0) {
            System.err.println("Usage: java -jar spoon-transformer.jar <input-source-directory>");
            System.exit(1);
        }

        String inputDir = args[0];

        // Create Spoon launcher
        Launcher launcher = new Launcher();
        launcher.getEnvironment().setComplianceLevel(11);
        launcher.addInputResource(inputDir);
        launcher.addProcessor(new JakartaServletMigrationProcessor());

        // Build the model
        CtModel model = launcher.buildModel();

        // Process the model
        launcher.process();

        // Write the transformed code back
        launcher.setSourceOutputDirectory(inputDir);
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation complete for directory: " + inputDir);
    }
}

