package github.chains;

import spoon.processing.AbstractProcessor;
import spoon.reflect.code.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.util.List;

/**
 * Spoon processor to migrate javax.servlet imports and references to jakarta.servlet
 */
public class JakartaServletMigrationProcessor extends AbstractProcessor<CtType<?>> {

    @Override
    public void process(CtType<?> type) {
        // Process imports
        List<CtImport> imports = type.getFactory().CompilationUnit().getImports();
        for (CtImport imp : imports) {
            if (imp.getReference() != null) {
                String importQualifiedName = imp.getReference().getQualifiedName();
                if (importQualifiedName.startsWith("javax.servlet")) {
                    // Replace javax.servlet with jakarta.servlet
                    String newImport = importQualifiedName.replace("javax.servlet", "jakarta.servlet");
                    imp.setReference(type.getFactory().Type().createReference(newImport));
                }
            }
        }

        // Process type references in the class
        type.accept(new JakartaServletReferenceVisitor());
    }
}

package github.chains;

import spoon.reflect.cu.position.NoSourcePosition;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.CtScanner;

/**
 * Visitor to replace javax.servlet type references with jakarta.servlet
 */
public class JakartaServletReferenceVisitor extends CtScanner {

    @Override
    public <T> void visitCtTypeReference(CtTypeReference<T> reference) {
        if (reference != null) {
            String qualifiedName = reference.getQualifiedName();
            if (qualifiedName != null && qualifiedName.startsWith("javax.servlet")) {
                // Replace javax.servlet with jakarta.servlet
                String newQualifiedName = qualifiedName.replace("javax.servlet", "jakarta.servlet");
                reference.setActualTypeArguments(null);
                reference.setSimpleName(null);
                reference.setPackage(null);
                reference.setQualifiedName(newQualifiedName);
            }
        }
        super.visitCtTypeReference(reference);
    }
}

