package github.chains;

import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.CtScanner;

/**
 * Visitor to replace javax.servlet type references with jakarta.servlet
 */
public class JakartaServletReferenceVisitor extends CtScanner {

    @Override
    public <T> void visitCtTypeReference(CtTypeReference<T> reference) {
        if (reference != null) {
            String qualifiedName = reference.getQualifiedName();
            if (qualifiedName != null && qualifiedName.startsWith("javax.servlet")) {
                // Replace javax.servlet with jakarta.servlet
                String newQualifiedName = qualifiedName.replace("javax.servlet", "jakarta.servlet");
                // Update the reference's qualified name
                reference.setQualifiedName(newQualifiedName);
            }
        }
        super.visitCtTypeReference(reference);
    }
}

